import { ZuploContext, ZuploRequest } from "@zuplo/runtime";

const EU_COUNTRIES = ["GB", "FR", "DE"];

export default async function (request: ZuploRequest, context: ZuploContext) {
  // Debug: log all headers and cf object
  const allHeaders: Record<string, string> = {};
  request.headers.forEach((value, key) => {
    allHeaders[key] = value;
  });
  context.log.info(`All headers: ${JSON.stringify(allHeaders)}`);

  // Try cf-ipcountry header first, then fall back to request.cf.country
  const cfIpCountry = request.headers.get("cf-ipcountry");
  // @ts-ignore - cf property exists on Cloudflare Workers Request
  const cfCountry = (request as any).cf?.country;
  context.log.info(`cf-ipcountry header: ${cfIpCountry}, cf.country: ${cfCountry}`);

  const country = cfIpCountry || cfCountry;
  let upstreamUrl: string;
  if (country && EU_COUNTRIES.includes(country)) {
    upstreamUrl = "https://echo.zuplo.io/eu/api/data";
  } else {
    upstreamUrl = "https://echo.zuplo.io/us/api/data";
  }

  context.log.info(`Routing to: ${upstreamUrl}`);
  const response = await fetch(upstreamUrl);
  return response;
}

